// ── Filtrar reseñas nuevas y formatearlas para Supabase ──────
// Fuente: Places API (New) — formato diferente a GBP API v4

// Respuesta de Places API
const placesResponse = $('GET Reviews (Places API)').first().json;

if (placesResponse.error) {
  const msg = placesResponse.error.message || JSON.stringify(placesResponse.error);
  if (msg.includes('SERVICE_DISABLED') || msg.includes('PERMISSION_DENIED') || msg.includes('billing')) {
    console.log('[Places] API deshabilitada o billing requerido:', msg);
    return []; // detiene limpiamente
  }
  throw new Error('Places API error: ' + msg);
}

// Places API devuelve reviews en el campo 'reviews' (máx 5)
const placesReviews = placesResponse.reviews || [];
const placeId = $('Config').first().json.PLACE_ID;

// IDs ya guardados en Supabase
const existingRows = $input.all();
const existingIds  = new Set(existingRows.map(r => r.json.review_id).filter(Boolean));

// Normalizar formato Places API → esquema Supabase
const newReviews = placesReviews
  .filter(r => {
    // review_id: último segmento de r.name ("places/{placeId}/reviews/{reviewId}")
    const rid = r.name ? r.name.split('/').pop() : null;
    return rid && !existingIds.has(rid);
  })
  .map(r => {
    const rid = r.name.split('/').pop();
    return {
      review_id:    rid,
      author:       r.authorAttribution?.displayName || 'Anónimo',
      rating:       r.rating || 5,                        // ya es entero 1-5
      text:         r.text?.text || '',
      date:         r.publishTime || new Date().toISOString(),
      status:       'pending',
      draft_response:     '',
      published_response: '',
      location_id:  'places/' + placeId
    };
  });

console.log(`[Places Sync] Total Places: ${placesReviews.length} | Ya en SB: ${existingIds.size} | Nuevas: ${newReviews.length}`);

return newReviews.map(r => ({ json: r }));
